dtsPropsFor.ConfirmDialog:
/** Controls visibility. The dialog renders nothing when false. */
  open: boolean;
  /** Heading shown at the top of the dialog. */
  title: string;
  /** Optional body content (string or JSX) shown under the title. */
  body?: React.ReactNode;
  /** Primary action button label. Default "Confirm". */
  confirmLabel?: string;
  /** Cancel button label. Default "Cancel". */
  cancelLabel?: string;
  /** Visual tone of the icon + primary button. Default "warning". */
  tone?: 'danger' | 'warning' | 'info';
  /** Called when the primary button is pressed (or Enter). */
  onConfirm: () => void;
  /** Called when Cancel, the backdrop, the close button, or Escape fires. */
  onCancel: () => void;
  /** Optional middle button label (e.g. "Save changes" in a 3-way dialog). */
  altLabel?: string;
  /** Called when the optional middle button is pressed. */
  onAlt?: () => void;

dtsPropsFor.IconPicker:
/** Currently selected lucide icon name (controlled). */
  value?: string;
  /** Called with the chosen lucide icon name. */
  onChange: (name: string) => void;
  /** Icon shown on the trigger button when no value is selected. Defaults to a Smile. */
  triggerFallbackIcon?: React.ReactNode;
  /** Optional label rendered next to the icon on the trigger. */
  triggerLabel?: string;
  /** Hex color for the thin ring around the trigger and selected grid cell. Default "#1a7a54". */
  accentColor?: string;

dtsPropsFor.EventIcon:
/** Lucide icon name (e.g. "Calendar", "Bell"). Falls back to Calendar when unknown or empty. */
  name?: string;
  /** Icon size in px. Default 18. */
  size?: number;
  /** Extra classes applied to the rendered icon (e.g. "text-eqc-green"). */
  className?: string;
